<template>
    <div>
        Hello<br>
        <button @click="searchTerm()">https://jsonplaceholder.typicode.com/posts</button><br>
        <button @click="clear()">비우기</button><br>
        <div id="dummyArea"></div>
    </div>
</template>

<script>
    export default {
        name: "Hello",
        created() {
        },
        methods: {
            searchTerm: function () {
                // this.axios.get("http://localhost/getBoardList")
                this.axios.get(`https://jsonplaceholder.typicode.com/posts`)
                    .then((data) => {
                        _.forEach(data.data, (item) => {
                            $("#dummyArea").append(item.title + "<br>");
                        });
                    });
            },
            clear: function () {
                $("#dummyArea").empty();
            }
        }
    }
</script>
<style scoped>

</style>



